import Link from "next/link";
import { prisma } from "@/src/lib/prisma";

export default async function HomePage() {
  const jobs = await prisma.job.findMany({
    orderBy: {
      createdAt: "desc",
    },
  });

  return (
    <main
      style={{
        padding: 40,
        maxWidth: 1000,
        margin: "0 auto",
        background: "linear-gradient(180deg, #f7f8fc 0%, #ffffff 70%)",
        color: "#0f172a",
        minHeight: "100vh",
      }}
    >
      <h1>My AI CRM</h1>
      <p style={{ marginTop: 8 }}>Submit websites and track jobs.</p>

      <div style={{ marginTop: 18 }}>
        <Link
          href="/new"
          style={{
            display: "inline-block",
            padding: "10px 14px",
            borderRadius: 10,
            border: "1px solid #111827",
            background: "#111827",
            color: "white",
            textDecoration: "none",
          }}
        >
          Create New Job
        </Link>
      </div>

      <div style={{ marginTop: 30 }}>
        <h2 style={{ marginBottom: 14 }}>Jobs</h2>

        {jobs.length === 0 ? (
          <p>No jobs yet.</p>
        ) : (
          <ul style={{ listStyle: "none", padding: 0, margin: 0 }}>
            {jobs.map((job) => (
              <li
                key={job.id}
                style={{
                  marginBottom: 12,
                  border: "1px solid #e5e7eb",
                  borderRadius: 12,
                  padding: 14,
                  background: "white",
                  boxShadow: "0 1px 10px rgba(15, 23, 42, 0.05)",
                }}
              >
                <Link href={`/jobs/${job.id}`}>
                  {job.url}
                </Link>{" "}
                — {job.status}
              </li>
            ))}
          </ul>
        )}
      </div>
    </main>
  );
}
